class Solution:
    def minSubArrayLen(self, target, nums):
        n = len(nums)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]
        best = n + 1
        for i in range(n):
            for j in range(i, n):
                if prefix[j + 1] - prefix[i] >= target:
                    best = min(best, j - i + 1)
                    break
        return 0 if best == n + 1 else best

