class Solution:
    def minSubArrayLen(self, target, nums):
        left = 0
        total = 0
        best = len(nums) + 1
        for right, v in enumerate(nums):
            total += v
            while total >= target:
                best = min(best, right - left + 1)
                total -= nums[left]
                left += 1
        return 0 if best == len(nums) + 1 else best

