var minSubArrayLen = function(target, nums) {
    let left = 0, total = 0, best = nums.length + 1;
    for (let right = 0; right < nums.length; right++) {
        total += nums[right];
        while (total >= target) {
            best = Math.min(best, right - left + 1);
            total -= nums[left];
            left++;
        }
    }
    return best === nums.length + 1 ? 0 : best;
};
